mapper.select:
SELECT a.SCH_ID , a.SCH_NM , a.ITLK_ID , (SELECT MAX(b.ITLK_NM|| ' (' || b.ITLK_STM_NM || ')') FROM PM_ITLK_RSC_MST b WHERE b.ITLK_ID = a.ITLK_ID) ITLK_NM , a.SCH_USE_YN , NVL(TO_CHAR(a.SCH_FR_DATE,'YYYY.MM.DD HH24:MI'),'-') SCH_FR_DATE , NVL(TO_CHAR(a.SCH_TO_DATE,'YYYY.MM.DD HH24:MI'),'-') SCH_TO_DATE , a.SCH_YR_TYP_CD , t_yr.CD_NM AS SCH_YR_TYP_NM , a.SCH_YR , a.SCH_MM_TYP_CD , t_mm.CD_NM AS SCH_MM_TYP_NM , a.SCH_MM , a.SCH_DD_TYP_CD , t_dd.CD_NM AS SCH_DD_TYP_NM , a.SCH_DD , a.SCH_DAYW_TYP_CD , t_dw.CD_NM AS SCH_DAYW_TYP_NM , a.SCH_DAYW , a.SCH_HH_TYP_CD , t_hh.CD_NM AS SCH_HH_TYP_NM , a.SCH_HH , a.SCH_MI_TYP_CD , t_mi.CD_NM AS SCH_MI_TYP_NM , a.SCH_MI , a.SCH_USE_YN , a.SCH_EXPL , (SELECT NVL(MAX(d.USER_NM),'manual') FROM AD_USER_MST d WHERE d.USER_ID = a.STM_FIR_REG_USER_ID) STM_FIR_REG_USER_NM , TO_CHAR(a.STM_FIR_REG_DATE,'YYYY.MM.DD HH24:MI') STM_FIR_REG_DATE , (SELECT NVL(MAX(e.USER_NM),'manual') FROM AD_USER_MST e WHERE e.USER_ID = a.STM_LAST_UPD_USER_ID) STM_LAST_UPD_USER_NM , TO_CHAR(a.STM_LAST_UPD_DATE,'YYYY.MM.DD HH24:MI') STM_LAST_UPD_DATE FROM PM_BAT_SCH_MST a, (SELECT * FROM AD_COMM_CD WHERE COMM_GRP_CD = 'SCH_YR_TYP_CD') t_yr, (SELECT * FROM AD_COMM_CD WHERE COMM_GRP_CD = 'SCH_YR_TYP_CD') t_mm, (SELECT * FROM AD_COMM_CD WHERE COMM_GRP_CD = 'SCH_YR_TYP_CD') t_dw, (SELECT * FROM AD_COMM_CD WHERE COMM_GRP_CD = 'SCH_YR_TYP_CD') t_dd, (SELECT * FROM AD_COMM_CD WHERE COMM_GRP_CD = 'SCH_YR_TYP_CD') t_hh, (SELECT * FROM AD_COMM_CD WHERE COMM_GRP_CD = 'SCH_YR_TYP_CD') t_mi WHERE 1=1 AND a.SCH_YR_TYP_CD = t_yr.COMM_CD AND a.SCH_MM_TYP_CD = t_mm.COMM_CD AND a.SCH_DAYW_TYP_CD = t_dw.COMM_CD AND a.SCH_DD_TYP_CD = t_dd.COMM_CD AND a.SCH_HH_TYP_CD = t_hh.COMM_CD AND a.SCH_MI_TYP_CD = t_mi.COMM_CD AND NVL(a.SCH_DEL_YN,'N') = 'N' AND a.SCH_GRP_CD = '03'
AND LOWER(a.SCH_NM) LIKE '%'||LOWER(#{schNm})||'%'
AND a.ITLK_ID = #{itlkId}
AND a.SCH_USE_YN = #{schUseYn}
ORDER BY STM_LAST_UPD_DATE DESC, a.SCH_NM

SELECT COUNT(*) OVER() TOTAL , c.SCH_INSTC_ID , c.SCH_ID , c.JOB_STS_CD , d.CD_NM AS JOB_STS_NM , c.JOB_PRG_RT || '%' JOB_PRG_RT , TO_CHAR(c.JOB_FR_DATE,'YYYY.MM.DD HH24:MI') JOB_FR_DATE , TO_CHAR(c.JOB_TO_DATE,'YYYY.MM.DD HH24:MI') JOB_TO_DATE , c.JOB_STS_MSG , c.JOB_SVR_NM , c.JOB_SVR_IP , c.IMMD_EXE_YN , c.IMMD_EXE_USER_ID , (SELECT NVL(MAX(f.USER_NM),'manual') FROM AD_USER_MST f WHERE f.USER_ID = c.IMMD_EXE_USER_ID) IMMD_EXE_USER_NM FROM PM_BAT_SCH_MST a, BA_SCH_MST b, BA_SCH_EXE_DTS c, (SELECT * FROM AD_COMM_CD WHERE COMM_GRP_CD = 'JOB_STS_CD') d, (SELECT * FROM AD_COMM_CD WHERE COMM_GRP_CD = 'SCH_GRP_CD' AND COMM_CD = '03') e WHERE 1=1 AND a.SCH_ID = b.SCH_ID AND a.SCH_ID = c.SCH_ID AND c.JOB_STS_CD = d.COMM_CD AND a.SCH_ID = #{schId} ORDER BY c.JOB_FR_DATE DESC
#{endRow}
#{startRow}
